6783   if (const auto *A = dyn_cast<Argument>(V)) {
6784     if (A->hasAttribute(Attribute::NoUndef) ||
6785         A->hasAttribute(Attribute::Dereferenceable) ||
6786         A->hasAttribute(Attribute::DereferenceableOrNull))
